```csharp
using cAlgo.API;

namespace cAlgo.Robots
{
    [Robot(TimeZone = TimeZones.UTC, AccessRights = AccessRights.None)]
    public class MovingAverageBot : Robot
    {
        [Parameter("Periods", DefaultValue = 20)]
        public int Periods { get; set; }

        private MovingAverage ma;

        protected override void OnStart()
        {
            ma = Indicators.MovingAverage(MarketSeries.Close, Periods, MovingAverageType.Exponential);
        }

        protected override void OnBar()
        {
            if (ma.Result.Last(2) < MarketSeries.Close.Last(2) && ma.Result.Last(1) > MarketSeries.Close.Last(1))
            {
                Trade.CreateMarketOrder(TradeType.Buy, Symbol, 10000);
            }
            else if (ma.Result.Last(2) > MarketSeries.Close.Last(2) && ma.Result.Last(1) < MarketSeries.Close.Last(1))
            {
                Trade.CreateMarketOrder(TradeType.Sell, Symbol, 10000);
            }
        }
    }
}
```

这个cBot首先定义了一个参数变量`Periods`，用于确定需要计算的平均周期数。然后，在`OnStart`方法中，它使用cTrader API中提供的`Indicators.MovingAverage`函数来计算指定期间的指数移动平均价格。对于此策略，我们使用的是指数移动平均类型，但您也可以选择其他平均线类型。

然后，在`OnBar`方法中，它检查平均价格是否与当前价格相交。如果平均价格从下方上升到上方，则发送一个买入信号；如果平均价格从上方下降到下方，则发送一个卖出信号。

