Here's an example of the Moving Average cBot code with these best practices in mind:

```csharp
using cAlgo.API;

namespace cAlgo.Robots
{
    [Robot(TimeZone = TimeZones.UTC, AccessRights = AccessRights.None)]
    public class MovingAverageBot : Robot
    {
        private MovingAverage _movingAverage;

        [Parameter("Candles", DefaultValue = 20)]
        public int Candles { get; set; }

        protected override void OnStart()
        {
            _movingAverage = Indicators.MovingAverage(MarketSeries.Close, Candles, MovingAverageType.Simple);
        }

        protected override void OnBar()
        {
            decimal lastTwoMa = _movingAverage.Result.Last(2);
            decimal lastTwoClose = MarketSeries.Close.Last(2);

            decimal lastMa = _movingAverage.Result.Last(1);
            decimal lastClose = MarketSeries.Close.Last(1);

            if (lastTwoMa < lastTwoClose && lastMa > lastClose)
            {
                Trade.CreateMarketOrder(TradeType.Buy, Symbol, 10000);
            }
            else if (lastTwoMa > lastTwoClose && lastMa < lastClose)
            {
                Trade.CreateMarketOrder(TradeType.Sell, Symbol, 10000);
            }
        }
    }
}
```

In this code, we have used descriptive variable names, and declared variables with appropriate data types. We've also used constants for the MovingAverageType to signify the moving average calculation type that we wish to use. Finally, we've organized the code into logical blocks, which makes it more readable and maintainable.
